            node.name,
            compatible.next() // compatible.intersperse(" ").collect::<String>()
        );
        for compati in node.compatibles() {
            if let Some(f) = driver_manager.get(compati) {
                ALL_DEVICES.lock().add_device(f(node));
                break;
