#[derive(Clone, Copy)]
struct RamMetadata {
    mode_bits: u32,
    uid: u32,
    gid: u32,
}

impl RamMetadata {
    fn new(mode: StatMode) -> Self {
        Self {
            mode_bits: mode.bits(),
            uid: 0,
            gid: 0,
        }
    }

    fn chmod(&mut self, mode: StatMode) {
        self.mode_bits = mode.bits();
    }

    fn chown(&mut self, uid: u32, gid: u32) {
        if uid != NO_CHANGE_ID {
            self.uid = uid;
        }
        if gid != NO_CHANGE_ID {
            self.gid = gid;
        }
        if uid != NO_CHANGE_ID || gid != NO_CHANGE_ID {
            self.mode_bits &= !(StatMode::SET_UID | StatMode::SET_GID).bits();
        }
    }

    fn mode(&self) -> StatMode {
        StatMode::from_bits_truncate(self.mode_bits)
    }
}

