    let mut task_id = TASK_ID.lock();
    *task_id += 1;
    *task_id
}

/// Get task through task id.
pub fn tid2task(tid: usize) -> Option<Arc<dyn AsyncTask>> {
    TASK_MAP.lock().get(&tid).cloned().map(|x| x.upgrade())?
}

/// Release task
pub fn release_task(tid: usize) {
    // Remove task from TASK_MAP
    TASK_MAP.lock().remove(&tid);
}

pub fn purge_exited_user_tasks() -> usize {
    let mut purged = 0;
    TASK_QUEUE.lock().retain(|item| {
        if item.task.get_task_type() == TaskType::BlankKernel {
            return true;
        }
        if item.task.exit_code().is_some() {
            TASK_MAP.lock().remove(&item.task.get_task_id());
            purged += 1;
            false
        } else {
            true
        }
    });
    purged
}

