/// Copy on write.
/// call this function when trigger store/instruction page fault.
/// copy page or remap page.
pub fn user_cow_int(task: Arc<UserTask>, _cx_ref: &mut TrapFrame, vaddr: VirtAddr) {
    let mut pcb = task.pcb.lock();
    let area = pcb.memset.iter_mut().find(|x| x.contains(vaddr.raw()));
    if let Some(area) = area {
        let finded = area.mtrackers.iter_mut().find(|x| x.vaddr == vaddr.floor());
        let ppn = match finded {
            Some(map_track) => {
                if area.mtype == MemType::Shared {
                    task.tcb.write().signal.insert(SignalNum::SEGV);
                    return;
                }
                // tips: this finded will consume a strong count.
                debug!("strong count: {}", Arc::strong_count(&map_track.tracker));
                if Arc::strong_count(&map_track.tracker) > 1 {
                    let src = map_track.tracker.0;
                    let dst = frame_alloc().expect("can't alloc @ user page fault");
                    unsafe {
                        dst.0
                            .get_mut_ptr::<u8>()
                            .copy_from_nonoverlapping(src.get_ptr(), PAGE_SIZE);
                    }
                    map_track.tracker = Arc::new(dst);
                }
                map_track.tracker.0
            }
            None => {
                let tracker = Arc::new(frame_alloc().expect("can't alloc frame in cow_fork_int"));
                let mtracker = MapTrack {
                    vaddr: vaddr.floor(),
                    tracker,
                    rwx: 0b111,
                };
                let offset = vaddr.floor().raw() + area.offset - area.start;
                if let Some(file) = &area.file {
                    file.readat(offset, mtracker.tracker.0.slice_mut_with_len(PAGE_SIZE))
                        .expect("can't read file in cow_fork_int");
                }
                let ppn = mtracker.tracker.0;
                area.mtrackers.push(mtracker);
                ppn
            }
        };

        drop(pcb);
        task.map(ppn, vaddr.floor(), MappingFlags::URWX);
    } else {
        task.tcb.write().signal.insert(SignalNum::SEGV);
    }
}

impl UserTaskContainer {
    /// Handle user interrupt.
    pub async fn handle_syscall(&self, cx_ref: &mut TrapFrame) -> UserTaskControlFlow {
        let ustart = get_ticks();
        #[cfg(target_arch = "loongarch64")]
        {
            cx_ref.prmd = (cx_ref.prmd & !0b111) | 0b111;
        }
        let reason = run_user_task(cx_ref);
        self.task.check_wall_deadline();
        if self.task.exit_code().is_some() {
            return UserTaskControlFlow::Break;
        }
        if matches!(reason, EscapeReason::Timer) && self.task.wall_deadline_fired() {
            yield_now().await;
            return UserTaskControlFlow::Break;
        }
        if matches!(reason, EscapeReason::SysCall) {
            self.task
                .inner_map(|inner| inner.tms.utime += (get_ticks() - ustart) as u64);

            let sstart = get_ticks();

            cx_ref.syscall_ok();
            self.task.check_wall_deadline();
            if self.task.exit_code().is_some() {
                return UserTaskControlFlow::Break;
            }
            let result = self
                .syscall(cx_ref[TrapFrameArgs::SYSCALL], cx_ref.args())
                .await
                .map_or_else(|e| -e.into_raw() as isize, |x| x as isize)
                as usize;
            self.task.check_wall_deadline();
            if self.task.exit_code().is_some() {
                return UserTaskControlFlow::Break;
            }

            debug!(
                "[task {}] syscall result: {}",
                self.task.get_task_id(),
                result as isize
            );

            cx_ref[TrapFrameArgs::RET] = result;
            self.task
                .inner_map(|inner| inner.tms.stime += (get_ticks() - sstart) as u64);
        }

        // let trap_type = trap_pre_handle(cx_ref);
        // match trap_type {
        //     arch::TrapType::Time => {
        //         // debug!("time interrupt from user");
        //     }
        //     arch::TrapType::Unknown => {
        //         debug!("unknown trap: {:#x?}", cx_ref);
        //         panic!("");
        //     }
        //     arch::TrapType::SupervisorExternal => {
        //         get_int_device().try_handle_interrupt(u32::MAX);
        //     }
        // }
        UserTaskControlFlow::Continue
    }
}

pub fn task_ilegal(task: &Arc<UserTask>, vaddr: VirtAddr, cx_ref: &mut TrapFrame) {
    let mut pcb = task.pcb.lock();
    let area = pcb.memset.iter_mut().find(|x| x.contains(vaddr.raw()));
    if let Some(area) = area {
        let finded = area.mtrackers.iter_mut().find(|x| x.vaddr == vaddr);
        match finded {
            Some(_) => {
                cx_ref[TrapFrameArgs::SEPC] += 2;
            }
            None => {
                task.tcb.write().signal.insert(SignalNum::ILL);
            }
        };
    } else {
        task.tcb.write().signal.insert(SignalNum::ILL);
    }
}

use crate::syscall::types::signal::SignalUserContext;
use crate::tasks::current_user_task;
use core::mem::size_of;
use executor::AsyncTask;
use libc_types::internal::SigAction;
use libc_types::signal::SignalNum;
use log::debug;
use polyhal_trap::trapframe::TrapFrameArgs;

use super::UserTaskContainer;

#[cfg(target_arch = "riscv64")]
const SIGNAL_RESTORER_CODE: [u8; 8] = [
    0x93, 0x08, 0xb0, 0x08, // li a7, 139
    0x73, 0x00, 0x00, 0x00, // ecall
];

#[cfg(target_arch = "loongarch64")]
const SIGNAL_RESTORER_CODE: [u8; 8] = [
    0x0b, 0x2c, 0x82, 0x03, // li.w $a7, 139
    0x00, 0x00, 0x2b, 0x00, // syscall 0
];

#[cfg(not(any(target_arch = "riscv64", target_arch = "loongarch64")))]
const SIGNAL_RESTORER_CODE: [u8; 0] = [];

#[cfg(target_arch = "riscv64")]
const SA_RESTORER: usize = 0x0400_0000;

fn install_signal_restorer(sp: usize) -> usize {
    let restorer = sp + size_of::<SignalUserContext>();
    va!(restorer)
        .slice_mut_with_len(SIGNAL_RESTORER_CODE.len())
        .copy_from_slice(&SIGNAL_RESTORER_CODE);
    #[cfg(target_arch = "riscv64")]
    unsafe {
        core::arch::asm!("fence.i");
    }
    restorer
}

impl UserTaskContainer {
    pub async fn handle_signal(&self, signal: SignalNum) {
        debug!(
            "handle signal: {:?} task_id: {}",
            signal,
            self.task.get_task_id()
        );

        // get the signal action for the signal.
        let sigaction = self.task.pcb.lock().sigaction[signal.num()].clone();

        if sigaction.handler == SigAction::SIG_IGN {
            // ignore signal if the handler of is SIG_IGN(1)
            return;
        } else if sigaction.handler == 0 || sigaction.handler == SigAction::SIG_DFL {
            // if there doesn't have signal handler.
            // Then use default handler. Exit or do nothing.
            if matches!(signal, SignalNum::CANCEL | SignalNum::SEGV | SignalNum::ILL) {
                current_user_task().exit_with_signal(signal.num());
            }
            return;
        }

        let cx_ref = self.task.force_cx_ref();
        // store task_mask and context.
        // alloc space for SignalUserContext at stack and align with 16 bytes.
        let sp = (cx_ref[TrapFrameArgs::SP]
            - size_of::<SignalUserContext>()
            - SIGNAL_RESTORER_CODE.len())
            & !0xF;
        let cx = unsafe { (sp as *mut SignalUserContext).as_mut().unwrap() };
        #[cfg(target_arch = "riscv64")]
        let restorer = if sigaction.flags & SA_RESTORER != 0 && sigaction.restorer > 1 {
            sigaction.restorer
        } else {
            install_signal_restorer(sp)
        };
        #[cfg(not(target_arch = "riscv64"))]
        let restorer = match sigaction.restorer {
            0 | 1 => install_signal_restorer(sp),
            restorer => restorer,
        };

        // change task context to do the signal.
        let mut tcb = self.task.tcb.write();
        cx.store_ctx(&cx_ref);
        cx.set_sig_mask(tcb.sigmask);

        tcb.sigmask = sigaction.mask;
        tcb.cx[TrapFrameArgs::SP] = sp;
        tcb.cx[TrapFrameArgs::SEPC] = sigaction.handler;
        tcb.cx[TrapFrameArgs::RA] = restorer;
        tcb.cx[TrapFrameArgs::ARG0] = signal.num();
        tcb.cx[TrapFrameArgs::ARG1] = 0;
        tcb.cx[TrapFrameArgs::ARG2] = cx as *mut SignalUserContext as usize;
        drop(tcb);
    }
}

