pub static MOUNTED_FS: Mutex<Vec<(PathBuf, DEntryNode)>> = Mutex::new(Vec::new());
static READONLY_MOUNTS: Mutex<Vec<PathBuf>> = Mutex::new(Vec::new());

#[derive(Clone)]
pub struct DEntryNode {
    pub fs: Arc<dyn FileSystem>,
    node: Arc<dyn INodeInterface>,
}

impl DEntryNode {
    #[inline]
    pub fn node(&self) -> Arc<dyn INodeInterface> {
        self.node.clone()
    }
}

/// 获取挂载的文件系统和挂载后的路径
///
/// # Arguments
///
/// - `path`  需要搜索的路径
///
/// # Returns
///
/// - [DEntryNode] `path` 对应挂载的文件系统
/// - [PathBuf]    `path` 减去挂载路径后的路径
///
pub fn get_mounted(path: &PathBuf) -> (DEntryNode, PathBuf) {
    let mounted = MOUNTED_FS.lock();
    let finded = mounted
        .iter()
        .rev()
        .find(|x| path.starts_with(&x.0))
        .unwrap();
    (finded.1.clone(), path.trim_start(&finded.0))
}

/// 挂载文件系统
///
/// # Arguments
///
/// - `fs`   需要挂载的文件系统
/// - `path` 文件系统挂载的路径
pub fn mount_fs(fs: Arc<dyn FileSystem>, path: &str) {
    if path != "/" {
        // 在挂载之前创建对应的文件夹
        let _ = File::open(path, OpenFlags::DIRECTORY | OpenFlags::CREAT);
    }
    let path = PathBuf::from(path);
    info!("SYSTEM FS mount {} @ {}", fs.name(), path);
    let node = fs.root_dir();
    let mut mounted = MOUNTED_FS.lock();
    mounted.retain(|x| x.0 != path);
    mounted.push((path, DEntryNode { fs, node }));
}

pub fn set_mount_readonly(path: &str, readonly: bool) {
    let path = PathBuf::from(path);
    let mut mounts = READONLY_MOUNTS.lock();
    mounts.retain(|mounted| *mounted != path);
    if readonly {
        mounts.push(path);
    }
}

pub fn is_readonly_path(path: &PathBuf) -> bool {
    READONLY_MOUNTS
        .lock()
        .iter()
        .rev()
        .any(|mounted| path.starts_with(mounted))
}

/// 取消挂载文件系统
///
/// # Arguments
///
/// - `path` 需要取消挂载的路径
pub fn umount(path: PathBuf) -> VfsResult<()> {
    MOUNTED_FS.lock().retain(|x| x.0 != path);
    READONLY_MOUNTS.lock().retain(|x| *x != path);
    Ok(())
}

use core::cmp;

use alloc::{
    collections::VecDeque,
    sync::{Arc, Weak},
};
use libc_types::{
    poll::PollEvent,
    types::{Stat, StatMode},
};
use sync::Mutex;
use syscalls::Errno;
use vfscore::{INodeInterface, VfsResult};

const PIPE_MIN_CAPACITY: usize = 4096;
pub const PIPE_DEFAULT_CAPACITY: usize = 0x50000;

struct PipeState {
    queue: VecDeque<u8>,
    capacity: usize,
}

pub struct PipeSender(Arc<Mutex<PipeState>>);

impl PipeSender {
    pub fn capacity(&self) -> usize {
        self.0.lock().capacity
    }

    pub fn set_capacity(&self, requested: usize) -> usize {
        let mut state = self.0.lock();
        state.capacity = cmp::max(cmp::max(requested, PIPE_MIN_CAPACITY), state.queue.len());
        state.capacity
    }
}

impl INodeInterface for PipeSender {
    fn writeat(&self, _offset: usize, buffer: &[u8]) -> VfsResult<usize> {
        log::warn!("write pipe:");
        let mut state = self.0.lock();
        if state.queue.len() >= state.capacity {
            return Err(Errno::EWOULDBLOCK);
        }
        let wlen = cmp::min(buffer.len(), state.capacity - state.queue.len());
        state.queue.extend(buffer[..wlen].iter());
        Ok(wlen)
    }

    fn poll(&self, events: PollEvent) -> VfsResult<PollEvent> {
        let mut res = PollEvent::NONE;
        let state = self.0.lock();
        if events.contains(PollEvent::OUT)
            && state.capacity.saturating_sub(state.queue.len()) >= PIPE_MIN_CAPACITY
        {
            res |= PollEvent::OUT;
        }
        Ok(res)
    }

    fn stat(&self, stat: &mut Stat) -> VfsResult<()> {
        stat.mode = StatMode::FIFO;
        Ok(())
    }
}

// pipe reader, just can read.
pub struct PipeReceiver {
    queue: Arc<Mutex<PipeState>>,
    sender: Weak<PipeSender>,
}

impl PipeReceiver {
    pub fn capacity(&self) -> usize {
        self.queue.lock().capacity
    }

    pub fn set_capacity(&self, requested: usize) -> usize {
        let mut state = self.queue.lock();
        state.capacity = cmp::max(cmp::max(requested, PIPE_MIN_CAPACITY), state.queue.len());
        state.capacity
    }
}

impl INodeInterface for PipeReceiver {
    fn readat(&self, _offset: usize, buffer: &mut [u8]) -> VfsResult<usize> {
        let mut state = self.queue.lock();
        let rlen = cmp::min(state.queue.len(), buffer.len());
        state
            .queue
            .drain(..rlen)
            .zip(buffer.iter_mut())
            .for_each(|(src, dst)| *dst = src);
        if rlen == 0 && Weak::strong_count(&self.sender) > 0 {
            Err(Errno::EWOULDBLOCK)
        } else {
            Ok(rlen)
        }
    }

    fn poll(&self, events: PollEvent) -> VfsResult<PollEvent> {
        let mut res = PollEvent::NONE;
        let state = self.queue.lock();
        if events.contains(PollEvent::IN) {
            if !state.queue.is_empty() {
                res |= PollEvent::IN;
            } else if Weak::strong_count(&self.sender) == 0 {
                res |= PollEvent::ERR;
            }
        }
        if events.contains(PollEvent::ERR)
            && state.queue.is_empty()
            && Weak::strong_count(&self.sender) == 0
        {
            res |= PollEvent::ERR;
        }
        Ok(res)
    }

    fn stat(&self, stat: &mut Stat) -> VfsResult<()> {
        stat.mode = StatMode::FIFO;
        Ok(())
    }
}

pub fn create_pipe() -> (Arc<PipeReceiver>, Arc<PipeSender>) {
    let queue = Arc::new(Mutex::new(PipeState {
        queue: VecDeque::new(),
        capacity: PIPE_DEFAULT_CAPACITY,
    }));
    let sender = Arc::new(PipeSender(queue.clone()));
    (
        Arc::new(PipeReceiver {
            queue: queue.clone(),
            sender: Arc::downgrade(&sender),
        }),
        sender,
    )
}

