#[derive(Clone)]
pub struct MemArea {
    pub mtype: MemType,
    pub mtrackers: Vec<MapTrack>,
    pub file: Option<Arc<dyn INodeInterface>>,
    pub offset: usize,
    pub start: usize,
    pub len: usize,
}

impl Debug for MemArea {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        f.debug_struct("MemArea")
            .field("mtype", &self.mtype)
            .field("mtrackers", &self.mtrackers)
            .field("start", &self.start)
            .field("len", &self.len)
            .finish()
    }
}

impl MemArea {
    /// Check the memory is overlapping.
    pub fn overlapping(&self, start: usize, end: usize) -> bool {
        let self_end = self.start + self.len;
        let res =
            !((start <= self.start && end <= self.start) || (start >= self_end && end >= self_end));
        res
    }

    /// write page to file
    pub fn write_page(&self, mtracker: &MapTrack) {
        assert!(self.file.is_some());
        if let Some(file) = &self.file {
            let offset = mtracker.vaddr.raw() + self.offset - self.start;
            file.writeat(offset, mtracker.tracker.0.slice_mut_with_len(PAGE_SIZE))
                .expect("can't write data back to mapped file.");
        }
    }

    /// Sub the memory from this memory area.
    /// the return value indicates whether the memory is splited.
    pub fn sub(&mut self, start: usize, end: usize, pt: &PageTable) -> Option<MemArea> {
        if !self.overlapping(start, end) {
            return None;
        }
        let old_start = self.start;
        let old_offset = self.offset;
        let range = self.start..self.start + self.len;
        let jrange = start..end;

        if range.contains(&start) && range.contains(&end) {
            self.len = start - self.start;
            let new_area_range = end..range.end;

            if let Some(_file) = &self.file {
                self.mtrackers
                    .iter()
                    .filter(|x| jrange.contains(&x.vaddr.raw()))
                    .for_each(|x| {
                        self.write_page(x);
                    });
            };
            // drop the sub memory area pages.
            self.mtrackers
                .extract_if(.., |x| jrange.contains(&x.vaddr.raw()))
                .for_each(|x| pt.unmap_page(x.vaddr));
            let right_trackers = self
                .mtrackers
                .extract_if(.., |x| new_area_range.contains(&x.vaddr.raw()))
                .collect();
            self.mtrackers.retain(|x| x.vaddr.raw() < start);
            return Some(MemArea {
                mtype: self.mtype,
                mtrackers: right_trackers,
                file: self.file.clone(),
                start: end,
                offset: old_offset + end - old_start,
                len: new_area_range.len(),
            });
        }

        if jrange.contains(&self.start) && jrange.contains(&range.end) {
            self.len = 0;
            // TIPS: This area will be remove outside this function.
            // So return the None.
            if let Some(_file) = &self.file {
                self.mtrackers
                    .iter()
                    .filter(|x| jrange.contains(&x.vaddr.raw()))
                    .for_each(|x| self.write_page(x));
            };
            self.mtrackers.retain(|x| {
                pt.unmap_page(x.vaddr);
                false
            });
            return None;
        }

        if range.contains(&start) {
            // self.len = cmp::min(start - self.start, self.len);
            self.len = start - self.start;
        } else if jrange.contains(&self.start) {
            self.len = self.start + self.len - end;
            self.offset += end - self.start;
            self.start = end;
        }
        if let Some(_file) = &self.file {
            self.mtrackers
                .iter()
                .filter(|x| jrange.contains(&x.vaddr.raw()))
                .for_each(|x| self.write_page(x));
        };
        // drop the sub memory area pages.
        let new_self_rang = self.start..self.start + self.len;
        self.mtrackers
            .extract_if(.., |x| !new_self_rang.contains(&x.vaddr.raw()))
            .for_each(|x| pt.unmap_page(x.vaddr));
        None
    }

    /// Check the memory area whether contains the specified address.
    pub fn contains(&self, addr: usize) -> bool {
        self.start <= addr && addr < self.start + self.len
    }
}

impl Drop for MemArea {
    fn drop(&mut self) {
        match &self.mtype {
            MemType::ShareFile => {
                let start = self.start;
                let len = self.len;
                let mapfile = self.file.clone().unwrap();
                for tracker in &self.mtrackers {
                    if Arc::strong_count(&tracker.tracker) > 1 {
                        continue;
                    }

                    let offset = tracker.vaddr.raw() - start;
                    let wlen = min(len - offset, PAGE_SIZE);

                    mapfile
                        .writeat(offset, tracker.tracker.0.slice_mut_with_len(wlen))
                        .expect("can't write data to file at drop");
                }
            }
            _ => {}
        }
    }
}

use alloc::{sync::Weak, vec::Vec};
use core::sync::atomic::{AtomicBool, AtomicU64, AtomicUsize, Ordering};
use core::time::Duration;

use crate::shutdown::shutdown;
use crate::tasks::UserTask;
use polyhal::timer::current_time;
use sync::Mutex;

const NANOS_PER_SEC: u64 = 1_000_000_000;

static GLOBAL_DEADLINE_NS: AtomicU64 = AtomicU64::new(0);
static GLOBAL_DEADLINE_FIRED: AtomicBool = AtomicBool::new(false);
static CHILD_TASK_BUDGET_NS: AtomicU64 = AtomicU64::new(0);
static CHILD_TASK_BUDGET_EXEMPT_ID: AtomicUsize = AtomicUsize::new(0);
static WATCHED_USER_TASKS: Mutex<Vec<Weak<UserTask>>> = Mutex::new(Vec::new());

pub fn duration_to_ns(duration: Duration) -> u64 {
    duration
        .as_secs()
        .saturating_mul(NANOS_PER_SEC)
        .saturating_add(duration.subsec_nanos() as u64)
}

pub fn current_time_ns() -> u64 {
    duration_to_ns(current_time())
}

pub fn arm_global_deadline_after(duration: Duration) {
    let deadline = duration_to_ns(current_time().saturating_add(duration));
    GLOBAL_DEADLINE_FIRED.store(false, Ordering::SeqCst);
    GLOBAL_DEADLINE_NS.store(deadline, Ordering::SeqCst);
}

pub fn disarm_global_deadline() {
    GLOBAL_DEADLINE_NS.store(0, Ordering::SeqCst);
}

pub fn set_child_task_budget(duration: Duration, exempt_task_id: usize) {
    CHILD_TASK_BUDGET_EXEMPT_ID.store(exempt_task_id, Ordering::SeqCst);
    CHILD_TASK_BUDGET_NS.store(duration_to_ns(duration), Ordering::SeqCst);
}

pub fn clear_child_task_budget() {
    CHILD_TASK_BUDGET_NS.store(0, Ordering::SeqCst);
    CHILD_TASK_BUDGET_EXEMPT_ID.store(0, Ordering::SeqCst);
}

pub fn active_child_task_budget_ns(task_id: usize) -> u64 {
    if CHILD_TASK_BUDGET_EXEMPT_ID.load(Ordering::Relaxed) == task_id {
        0
    } else {
        CHILD_TASK_BUDGET_NS.load(Ordering::Relaxed)
    }
}

pub fn new_child_task_deadline_ns(task_id: usize) -> u64 {
    let budget = active_child_task_budget_ns(task_id);
    if budget == 0 {
        0
    } else {
        current_time_ns().saturating_add(budget)
    }
}

pub fn deadline_after(duration: Duration) -> u64 {
    duration_to_ns(current_time().saturating_add(duration))
}

pub fn register_user_task(task: Weak<UserTask>) {
    let mut tasks = WATCHED_USER_TASKS.lock();
    // Prune dead entries HERE (outside the timer IRQ). Dropping the last Weak of a
    // dead task deallocates; doing that inside the timer IRQ can re-enter the global
    // heap spinlock held by the interrupted task -> single-core deadlock.
    tasks.retain(|t| t.strong_count() > 0);
    tasks.push(task);
}

pub fn check_user_task_deadlines_from_timer() {
    let Some(tasks) = WATCHED_USER_TASKS.try_lock() else {
        return;
    };
    // Allocation-free: only upgrade + check the deadline; never drop a Weak here
    // (that may dealloc). Dead entries are pruned in register_user_task instead.
    for entry in tasks.iter() {
        if let Some(task) = entry.upgrade() {
            task.check_wall_deadline_from_timer();
        }
    }
}

pub fn check_global_deadline_from_timer() {
    let deadline = GLOBAL_DEADLINE_NS.load(Ordering::Relaxed);
    if deadline == 0 {
        return;
    }
    if duration_to_ns(current_time()) < deadline {
        return;
    }
    if GLOBAL_DEADLINE_FIRED.swap(true, Ordering::SeqCst) {
        return;
    }

    println!("kernel watchdog: global deadline reached from timer interrupt; forcing shutdown");
    shutdown();
}

use alloc::sync::Arc;
use alloc::vec::Vec;
use devices::device::{BlkDriver, DeviceType, Driver};
